import type { ComponentProps } from 'react';
import { Popover as PopoverPrimitive } from '@base-ui/react/popover';
import { clsx } from 'clsx';
import { PopupArrowIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Popover.module.css';

type PopoverContentProps = PopoverPrimitive.Popup.Props & {
  showArrow?: boolean;
  side?: PopoverPrimitive.Positioner.Props['side'];
  sideOffset?: PopoverPrimitive.Positioner.Props['sideOffset'];
  align?: PopoverPrimitive.Positioner.Props['align'];
  alignOffset?: PopoverPrimitive.Positioner.Props['alignOffset'];
  arrowPadding?: PopoverPrimitive.Positioner.Props['arrowPadding'];
  collisionAvoidance?: PopoverPrimitive.Positioner.Props['collisionAvoidance'];
  collisionBoundary?: PopoverPrimitive.Positioner.Props['collisionBoundary'];
  collisionPadding?: PopoverPrimitive.Positioner.Props['collisionPadding'];
};

const POPOVER_CONTENT_SIDE_OFFSET = 8;
const Popover = PopoverPrimitive.Root;
const createPopoverHandle = PopoverPrimitive.createHandle;

function PopoverTrigger({ className, render, ...props }: PopoverPrimitive.Trigger.Props) {
  return (
    <PopoverPrimitive.Trigger
      data-slot="popover-trigger"
      render={render}
      className={render ? className : mergeClassName(className, styles.trigger)}
      {...props}
    />
  );
}

function PopoverPortal({ className, ...props }: PopoverPrimitive.Portal.Props) {
  return <PopoverPrimitive.Portal data-slot="popover-portal" className={className} {...props} />;
}

function PopoverBackdrop({ className, ...props }: PopoverPrimitive.Backdrop.Props) {
  return (
    <PopoverPrimitive.Backdrop
      data-slot="popover-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function PopoverPositioner({ className, ...props }: PopoverPrimitive.Positioner.Props) {
  return (
    <PopoverPrimitive.Positioner
      data-slot="popover-positioner"
      className={mergeClassName(className, styles.positioner)}
      {...props}
    />
  );
}

function PopoverPopup({ className, ...props }: PopoverPrimitive.Popup.Props) {
  return (
    <PopoverPrimitive.Popup
      data-slot="popover-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function PopoverViewport({ className, ...props }: PopoverPrimitive.Viewport.Props) {
  return (
    <PopoverPrimitive.Viewport
      data-slot="popover-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
}

function PopoverArrow({ className, children, ...props }: PopoverPrimitive.Arrow.Props) {
  return (
    <PopoverPrimitive.Arrow
      data-slot="popover-arrow"
      className={mergeClassName(className, styles.arrow)}
      {...props}
    >
      {children ?? (
        <PopupArrowIcon
          className={styles.arrowSvg}
          fillClassName={styles.arrowFill}
          outerStrokeClassName={styles.arrowOuterStroke}
          innerStrokeClassName={styles.arrowInnerStroke}
        />
      )}
    </PopoverPrimitive.Arrow>
  );
}

function PopoverTitle({ className, ...props }: PopoverPrimitive.Title.Props) {
  return (
    <PopoverPrimitive.Title
      data-slot="popover-title"
      className={mergeClassName(className, styles.title)}
      {...props}
    />
  );
}

function PopoverDescription({ className, ...props }: PopoverPrimitive.Description.Props) {
  return (
    <PopoverPrimitive.Description
      data-slot="popover-description"
      className={mergeClassName(className, styles.description)}
      {...props}
    />
  );
}

function PopoverHeader({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="popover-header" className={clsx(styles.header, className)} {...props} />;
}

function PopoverBody({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="popover-body" className={clsx(styles.body, className)} {...props} />;
}

function PopoverFooter({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="popover-footer" className={clsx(styles.footer, className)} {...props} />;
}

function PopoverClose({ className, ...props }: PopoverPrimitive.Close.Props) {
  return (
    <PopoverPrimitive.Close
      data-slot="popover-close"
      className={mergeClassName(className, styles.close)}
      {...props}
    />
  );
}

function PopoverContent({
  className,
  children,
  showArrow = false,
  side,
  sideOffset = POPOVER_CONTENT_SIDE_OFFSET,
  align,
  alignOffset,
  arrowPadding,
  collisionAvoidance,
  collisionBoundary,
  collisionPadding,
  ...popupProps
}: PopoverContentProps) {
  return (
    <PopoverPortal>
      <PopoverPositioner
        side={side}
        sideOffset={sideOffset}
        align={align}
        alignOffset={alignOffset}
        arrowPadding={arrowPadding}
        collisionAvoidance={collisionAvoidance}
        collisionBoundary={collisionBoundary}
        collisionPadding={collisionPadding}
      >
        <PopoverPopup className={className} {...popupProps}>
          {showArrow ? <PopoverArrow /> : null}
          {children}
        </PopoverPopup>
      </PopoverPositioner>
    </PopoverPortal>
  );
}

export {
  Popover,
  createPopoverHandle,
  PopoverTrigger,
  PopoverPortal,
  PopoverBackdrop,
  PopoverPositioner,
  PopoverPopup,
  PopoverViewport,
  PopoverArrow,
  PopoverTitle,
  PopoverDescription,
  PopoverHeader,
  PopoverBody,
  PopoverFooter,
  PopoverClose,
  PopoverContent,
};

@layer ui.components {
  .trigger,
  .close {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--popover-control-height, var(--size-lg));
    margin: 0;
    padding: var(--popover-control-padding-y, 0.5rem) var(--popover-control-padding-x, 0.875rem);
    border: var(--popover-control-border-width, var(--border-width-sm)) solid
      var(--popover-control-border-color, var(--color-border));
    border-radius: var(--popover-control-radius, var(--radius-md));
    background-color: var(--popover-control-bg, var(--color-background));
    color: var(--popover-control-color, var(--color-foreground));
    font: inherit;
    font-size: var(--popover-control-font-size, var(--text-md));
    line-height: var(--popover-control-line-height, var(--line-height-text-md));
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--popover-transition, var(--transition-default)),
      border-color var(--popover-transition, var(--transition-default)),
      color var(--popover-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--popover-control-bg-hover, var(--color-accent));
      }
    }

    &:active,
    &[data-popup-open] {
      background-color: var(
        --popover-control-bg-active,
        var(--popover-control-bg-hover, var(--color-accent))
      );
    }

    &:focus-visible {
      outline: var(
          --popover-focus-ring-width,
          var(--popover-control-border-width, var(--border-width-sm))
        )
        solid var(--popover-focus-ring-color, var(--color-ring));
      outline-offset: calc(
        var(
            --popover-focus-ring-width,
            var(--popover-control-border-width, var(--border-width-sm))
          ) *
          -1
      );
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--popover-disabled-opacity, var(--opacity-disabled));
    }
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--popover-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--popover-backdrop-blur, 4px)));
    transition:
      opacity var(--popover-backdrop-transition, var(--transition-default)),
      backdrop-filter var(--popover-backdrop-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--popover-backdrop-starting-opacity, 0);
      backdrop-filter: var(--popover-backdrop-starting-blur, none);
    }

    &[data-ending-style] {
      opacity: var(--popover-backdrop-ending-opacity, 0);
      backdrop-filter: var(--popover-backdrop-ending-blur, none);
    }
  }

  .positioner {
    z-index: var(--z-popup);
    width: var(--positioner-width);
    height: var(--positioner-height);
    max-width: var(--available-width);
    outline: 0;
  }

  .popup {
    box-sizing: border-box;
    width: var(--popup-width, var(--popover-width, auto));
    height: var(--popup-height, var(--popover-height, auto));
    min-width: min(var(--popover-min-width, 16rem), var(--available-width));
    max-width: min(var(--popover-max-width, 28rem), var(--available-width));
    max-height: min(var(--popover-max-height, 24rem), var(--available-height, 100dvh));
    overflow: visible;
    padding: var(--popover-padding-y, 1rem) var(--popover-padding-x, 1rem);
    border: 0;
    border-radius: var(--popover-radius, var(--radius-md));
    background-color: var(--popover-bg, var(--color-popover));
    color: var(--popover-color, var(--color-popover-foreground));
    outline: var(--popover-border-width, var(--border-width-sm)) solid
      var(--popover-border-color, var(--color-border));
    box-shadow: var(--popover-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);
    transition:
      transform var(--popover-transition, var(--duration-fast)),
      opacity var(--popover-transition, var(--duration-fast)),
      translate var(--popover-transition, var(--duration-fast));

    &[data-starting-style] {
      opacity: var(--popover-popup-starting-opacity, 0);
      translate: var(--popover-popup-starting-translate-x, 0)
        var(--popover-popup-starting-translate-y, 0);
      transform: scale(var(--popover-popup-starting-scale, var(--scale-popup)));
    }

    &[data-ending-style] {
      opacity: var(--popover-popup-ending-opacity, 0);
      translate: var(--popover-popup-ending-translate-x, 0)
        var(--popover-popup-ending-translate-y, 0);
      transform: scale(var(--popover-popup-ending-scale, var(--scale-popup)));
    }
  }

  .viewport {
    position: relative;
    width: 100%;
    height: 100%;
    overflow: clip;

    & > [data-current],
    & > [data-previous] {
      width: var(--popup-width, auto);
      transition:
        translate var(--popover-viewport-transition, var(--duration-normal)),
        opacity var(--popover-viewport-transition, var(--duration-normal));
    }

    & > [data-current] {
      opacity: 1;
      translate: 0;
    }

    &[data-activation-direction~='left'] {
      & > [data-current][data-starting-style],
      & > [data-previous][data-ending-style] {
        opacity: 0;
        translate: calc(var(--popover-viewport-offset, 1rem) * -1) 0;
      }
    }

    &[data-activation-direction~='right'] {
      & > [data-current][data-starting-style],
      & > [data-previous][data-ending-style] {
        opacity: 0;
        translate: var(--popover-viewport-offset, 1rem) 0;
      }
    }
  }

  .arrow {
    display: flex;
    color: var(--popover-bg, var(--color-popover));

    &[data-side='top'] {
      bottom: calc(var(--popover-arrow-size, 8px) * -1);
      rotate: 180deg;
    }

    &[data-side='bottom'] {
      top: calc(var(--popover-arrow-size, 8px) * -1);
    }

    &[data-side='left'] {
      right: calc(var(--popover-arrow-inline-offset, 13px) * -1);
      rotate: 90deg;
    }

    &[data-side='right'] {
      left: calc(var(--popover-arrow-inline-offset, 13px) * -1);
      rotate: -90deg;
    }
  }

  .arrowSvg {
    display: block;
    width: var(--popover-arrow-width, 1.25rem);
    height: var(--popover-arrow-height, 0.625rem);
    overflow: visible;
  }

  .arrowFill {
    fill: currentColor;
  }

  .arrowOuterStroke {
    fill: var(--popover-arrow-stroke-color, var(--popover-border-color, var(--color-border)));
  }

  .arrowInnerStroke {
    fill: var(--popover-bg, var(--color-popover));
  }

  .title {
    margin: 0;
    color: var(--popover-title-color, var(--popover-color, var(--color-popover-foreground)));
    font-size: var(--popover-title-font-size, var(--text-md));
    font-weight: var(--popover-title-font-weight, var(--weight-semibold));
    line-height: var(--popover-title-line-height, var(--line-height-text-md));
  }

  .description {
    margin: var(--popover-description-margin, 0);
    color: var(--popover-description-color, var(--color-muted-foreground));
    font-size: var(--popover-description-font-size, var(--text-sm));
    line-height: var(--popover-description-line-height, var(--line-height-text-sm));
  }

  .header {
    display: grid;
    gap: var(--popover-header-gap, var(--spacing-1));
  }

  .body {
    margin: var(--popover-body-margin, 0);
  }

  .footer {
    display: flex;
    align-items: center;
    justify-content: var(--popover-footer-justify, flex-end);
    gap: var(--popover-footer-gap, var(--spacing-2));
    margin: var(--popover-footer-margin, var(--spacing-3) 0 0);
  }
}
